<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  html, body { width: 100%; height: 100%; overflow: hidden; }
  body {
    font-family: "Ubuntu", "Segoe UI", "Cantarell", system-ui, sans-serif;
    color: #f2f0ee;
    user-select: none;
  }

  /* ---------- Desktop ---------- */
  #desktop {
    position: fixed;
    inset: 0;
    background:
      radial-gradient(ellipse at 25% 20%, #5e2750 0%, transparent 55%),
      radial-gradient(ellipse at 80% 85%, #772953 0%, transparent 55%),
      linear-gradient(135deg, #2c001e 0%, #3a1730 45%, #48214a 100%);
    overflow: hidden;
  }

  /* faint desktop label */
  #desktop::after {
    content: "";
    position: absolute;
    inset: 0;
    background:
      repeating-linear-gradient(45deg, rgba(255,255,255,0.012) 0 2px, transparent 2px 4px);
    pointer-events: none;
  }

  /* ---------- Top bar ---------- */
  #topbar {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 28px;
    background: rgba(20, 12, 18, 0.85);
    backdrop-filter: blur(6px);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 13px;
    letter-spacing: 0.3px;
    z-index: 5000;
    border-bottom: 1px solid rgba(255,255,255,0.06);
  }
  #topbar .activities { position: absolute; left: 12px; opacity: 0.85; }
  #clock { position: absolute; right: 14px; opacity: 0.9; font-variant-numeric: tabular-nums; }

  /* ---------- Taskbar / Dock ---------- */
  #taskbar {
    position: absolute;
    left: 10px;
    top: 42px;
    bottom: 14px;
    width: 62px;
    background: rgba(15, 8, 13, 0.72);
    backdrop-filter: blur(8px);
    border: 1px solid rgba(255,255,255,0.07);
    border-radius: 14px;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 12px;
    padding: 12px 0;
    z-index: 4000;
    box-shadow: 0 8px 30px rgba(0,0,0,0.4);
  }
  .launcher {
    width: 46px; height: 46px;
    border: none;
    border-radius: 12px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 24px;
    color: #fff;
    transition: transform 0.12s ease, filter 0.12s ease;
    position: relative;
  }
  .launcher:hover { transform: scale(1.08); filter: brightness(1.12); }
  .launcher:active { transform: scale(0.96); }
  #open-files { background: linear-gradient(145deg, #e07b39, #c34a1a); }
  #open-notepad { background: linear-gradient(145deg, #4a6fa5, #2b4570); }
  .launcher.running::after {
    content: "";
    position: absolute;
    left: -7px; top: 50%;
    transform: translateY(-50%);
    width: 4px; height: 20px;
    border-radius: 2px;
    background: #e95420;
  }

  /* ---------- Windows ---------- */
  .window {
    position: absolute;
    min-width: 360px;
    min-height: 240px;
    background: #2b2b2b;
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 10px;
    box-shadow: 0 18px 50px rgba(0,0,0,0.55);
    display: none;
    flex-direction: column;
    overflow: hidden;
    z-index: 100;
  }
  .window.open { display: flex; }
  .titlebar {
    height: 38px;
    background: linear-gradient(#3a3a3a, #303030);
    display: flex;
    align-items: center;
    padding: 0 10px;
    gap: 8px;
    cursor: move;
    border-bottom: 1px solid rgba(0,0,0,0.4);
    flex: 0 0 auto;
  }
  .titlebar .title { font-size: 13px; font-weight: 600; opacity: 0.92; flex: 1; }
  .win-btn {
    width: 15px; height: 15px;
    border-radius: 50%;
    border: none;
    cursor: pointer;
  }
  .win-close { background: #e95420; }
  .win-close:hover { filter: brightness(1.2); }
  .win-min { background: #f5c344; }
  .win-max { background: #57a94a; }

  /* ---------- Files app ---------- */
  #files-window { width: 640px; height: 440px; left: 130px; top: 90px; }
  .files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 10px;
    background: #333;
    border-bottom: 1px solid rgba(0,0,0,0.35);
    flex: 0 0 auto;
  }
  .tbtn {
    background: #4a4a4a;
    border: 1px solid rgba(255,255,255,0.08);
    color: #eee;
    border-radius: 6px;
    padding: 5px 11px;
    font-size: 13px;
    cursor: pointer;
  }
  .tbtn:hover { background: #565656; }
  .tbtn:active { background: #3f3f3f; }
  #files-path {
    flex: 1;
    background: #232323;
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 6px;
    padding: 6px 10px;
    font-size: 13px;
    font-family: "Ubuntu Mono", monospace;
    color: #bfe0c0;
    overflow: hidden;
    white-space: nowrap;
    text-overflow: ellipsis;
  }
  #files-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(96px, 1fr));
    gap: 6px;
    align-content: start;
    background: #262626;
  }
  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 6px;
    padding: 10px 4px;
    border-radius: 8px;
    cursor: pointer;
    text-align: center;
    transition: background 0.1s;
  }
  .fs-item:hover { background: rgba(255,255,255,0.06); }
  .fs-item.selected { background: rgba(233,84,32,0.28); }
  .fs-item .icon { font-size: 34px; line-height: 1; }
  .fs-item .name {
    font-size: 12px;
    word-break: break-word;
    max-width: 92px;
    line-height: 1.2;
  }
  .files-empty {
    grid-column: 1 / -1;
    opacity: 0.5;
    font-size: 13px;
    padding: 20px;
    text-align: center;
  }

  /* ---------- Notepad app ---------- */
  #notepad-window { width: 560px; height: 420px; left: 300px; top: 140px; }
  #tabs {
    display: flex;
    align-items: stretch;
    background: #262626;
    border-bottom: 1px solid rgba(0,0,0,0.4);
    overflow-x: auto;
    flex: 0 0 auto;
    min-height: 34px;
  }
  #tabs::-webkit-scrollbar { height: 4px; }
  .tab {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 6px 10px;
    font-size: 12px;
    background: #2f2f2f;
    border-right: 1px solid rgba(0,0,0,0.4);
    cursor: pointer;
    white-space: nowrap;
    max-width: 160px;
    color: #cfcfcf;
  }
  .tab:hover { background: #383838; }
  .tab.active { background: #3d3d3d; color: #fff; border-bottom: 2px solid #e95420; }
  .tab .tab-name {
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: 120px;
  }
  .tab .tab-close {
    font-size: 14px;
    opacity: 0.6;
    border-radius: 3px;
    padding: 0 3px;
    line-height: 1;
  }
  .tab .tab-close:hover { opacity: 1; background: rgba(255,255,255,0.15); }
  #new-tab {
    flex: 0 0 auto;
    padding: 6px 12px;
    font-size: 16px;
    background: transparent;
    border: none;
    color: #ccc;
    cursor: pointer;
  }
  #new-tab:hover { background: #383838; color: #fff; }
  #editor {
    flex: 1;
    width: 100%;
    resize: none;
    border: none;
    outline: none;
    background: #1e1e1e;
    color: #eaeaea;
    font-family: "Ubuntu Mono", "Consolas", monospace;
    font-size: 14px;
    line-height: 1.5;
    padding: 12px 14px;
    user-select: text;
  }
</style>
</head>
<body>
<div id="desktop">
  <div id="topbar">
    <span class="activities">Activities</span>
    <span>Ubuntu Desktop</span>
    <span id="clock">--:--</span>
  </div>

  <div id="taskbar">
    <button class="launcher" id="open-files" title="Files">🗂️</button>
    <button class="launcher" id="open-notepad" title="Notepad">📝</button>
  </div>

  <!-- Files window -->
  <div class="window" id="files-window">
    <div class="titlebar" data-win="files-window">
      <button class="win-btn win-close" title="Close"></button>
      <button class="win-btn win-min" title="Minimize"></button>
      <button class="win-btn win-max" title="Maximize"></button>
      <span class="title">Files</span>
    </div>
    <div class="files-toolbar">
      <button class="tbtn" id="files-up" title="Parent folder">↑ Up</button>
      <button class="tbtn" id="files-home" title="Home">⌂ Home</button>
      <div id="files-path">/</div>
    </div>
    <div id="files-list"></div>
  </div>

  <!-- Notepad window -->
  <div class="window" id="notepad-window">
    <div class="titlebar" data-win="notepad-window">
      <button class="win-btn win-close" title="Close"></button>
      <button class="win-btn win-min" title="Minimize"></button>
      <button class="win-btn win-max" title="Maximize"></button>
      <span class="title">Notepad</span>
    </div>
    <div id="tabs">
      <button id="new-tab" title="New tab">＋</button>
    </div>
    <textarea id="editor" spellcheck="false" placeholder="Type here…"></textarea>
  </div>
</div>

<script>
(function () {
  "use strict";

  /* ============ Clock ============ */
  function tick() {
    var d = new Date();
    var h = String(d.getHours()).padStart(2, "0");
    var m = String(d.getMinutes()).padStart(2, "0");
    document.getElementById("clock").textContent = h + ":" + m;
  }
  tick();
  setInterval(tick, 1000);

  /* ============ Window management ============ */
  var zTop = 100;
  function bringToFront(win) { win.style.zIndex = ++zTop; }

  function setupWindow(winId, launcherId) {
    var win = document.getElementById(winId);
    var launcher = document.getElementById(launcherId);
    var closeBtn = win.querySelector(".win-close");
    var minBtn = win.querySelector(".win-min");

    function open() {
      win.classList.add("open");
      launcher.classList.add("running");
      bringToFront(win);
    }
    function hide() {
      win.classList.remove("open");
      launcher.classList.remove("running");
    }

    launcher.addEventListener("click", function () {
      if (win.classList.contains("open")) {
        bringToFront(win);
      } else {
        open();
      }
    });
    closeBtn.addEventListener("click", hide);
    if (minBtn) minBtn.addEventListener("click", hide);

    win.addEventListener("mousedown", function () { bringToFront(win); });
    return { open: open, hide: hide, win: win };
  }

  var filesWin = setupWindow("files-window", "open-files");
  var notepadWin = setupWindow("notepad-window", "open-notepad");

  /* Maximize toggle */
  document.querySelectorAll(".win-max").forEach(function (btn) {
    btn.addEventListener("click", function () {
      var win = btn.closest(".window");
      if (win.dataset.maxed === "1") {
        win.style.left = win.dataset.px;
        win.style.top = win.dataset.py;
        win.style.width = win.dataset.pw;
        win.style.height = win.dataset.ph;
        win.dataset.maxed = "0";
      } else {
        win.dataset.px = win.style.left;
        win.dataset.py = win.style.top;
        win.dataset.pw = win.style.width;
        win.dataset.ph = win.style.height;
        win.style.left = "82px";
        win.style.top = "34px";
        win.style.width = "calc(100vw - 96px)";
        win.style.height = "calc(100vh - 52px)";
        win.dataset.maxed = "1";
      }
    });
  });

  /* ============ Window dragging ============ */
  document.querySelectorAll(".titlebar").forEach(function (bar) {
    var win = document.getElementById(bar.dataset.win);
    var dragging = false, ox = 0, oy = 0;
    bar.addEventListener("mousedown", function (e) {
      if (e.target.classList.contains("win-btn")) return;
      dragging = true;
      var r = win.getBoundingClientRect();
      ox = e.clientX - r.left;
      oy = e.clientY - r.top;
      bringToFront(win);
      e.preventDefault();
    });
    document.addEventListener("mousemove", function (e) {
      if (!dragging) return;
      var x = e.clientX - ox;
      var y = e.clientY - oy;
      x = Math.max(-40, Math.min(x, window.innerWidth - 60));
      y = Math.max(28, Math.min(y, window.innerHeight - 40));
      win.style.left = x + "px";
      win.style.top = y + "px";
    });
    document.addEventListener("mouseup", function () { dragging = false; });
  });

  /* ============ Files app ============ */
  // Fake Linux filesystem. Folders have `children`; files are leaves.
  var FS = {
    bin: { type: "dir", children: {
      "bash": { type: "file" }, "ls": { type: "file" }, "cat": { type: "file" },
      "grep": { type: "file" }, "cp": { type: "file" }, "mv": { type: "file" }
    }},
    etc: { type: "dir", children: {
      "hostname": { type: "file" }, "hosts": { type: "file" },
      "passwd": { type: "file" }, "fstab": { type: "file" },
      "apt": { type: "dir", children: { "sources.list": { type: "file" } } }
    }},
    home: { type: "dir", children: {
      user: { type: "dir", children: {
        "Documents": { type: "dir", children: {
          "resume.pdf": { type: "file" }, "notes.txt": { type: "file" },
          "budget.ods": { type: "file" }
        }},
        "Downloads": { type: "dir", children: {
          "ubuntu-24.04.iso": { type: "file" }, "photo.zip": { type: "file" }
        }},
        "Pictures": { type: "dir", children: {
          "wallpaper.png": { type: "file" }, "screenshot.png": { type: "file" },
          "Vacation": { type: "dir", children: { "beach.jpg": { type: "file" } } }
        }},
        "Music": { type: "dir", children: { "song.mp3": { type: "file" } } },
        ".bashrc": { type: "file" },
        "todo.txt": { type: "file" }
      }}
    }},
    usr: { type: "dir", children: {
      "bin": { type: "dir", children: { "python3": { type: "file" }, "node": { type: "file" } } },
      "lib": { type: "dir", children: {} },
      "share": { type: "dir", children: { "applications": { type: "dir", children: {} } } }
    }},
    var: { type: "dir", children: {
      "log": { type: "dir", children: { "syslog": { type: "file" }, "auth.log": { type: "file" } } },
      "tmp": { type: "dir", children: {} },
      "www": { type: "dir", children: { "html": { type: "dir", children: { "index.html": { type: "file" } } } } }
    }}
  };

  var currentPath = []; // array of segments; [] === "/"

  function nodeAtPath(segs) {
    var node = { type: "dir", children: FS };
    for (var i = 0; i < segs.length; i++) {
      if (!node.children || !node.children[segs[i]] || node.children[segs[i]].type !== "dir") {
        return null;
      }
      node = node.children[segs[i]];
    }
    return node;
  }

  function pathString(segs) {
    return "/" + segs.join("/");
  }

  function iconFor(name, isDir) {
    if (isDir) return "📁";
    var ext = name.split(".").pop().toLowerCase();
    if (["png", "jpg", "jpeg", "gif", "bmp"].indexOf(ext) >= 0) return "🖼️";
    if (["txt", "md", "log", "list", "conf"].indexOf(ext) >= 0) return "📄";
    if (["pdf"].indexOf(ext) >= 0) return "📕";
    if (["zip", "iso", "tar", "gz"].indexOf(ext) >= 0) return "🗜️";
    if (["mp3", "wav", "ogg"].indexOf(ext) >= 0) return "🎵";
    if (name === ".bashrc" || ext === "sh") return "⚙️";
    return "📄";
  }

  function renderFiles() {
    document.getElementById("files-path").textContent = pathString(currentPath);
    var list = document.getElementById("files-list");
    list.innerHTML = "";
    var node = nodeAtPath(currentPath);
    var children = (node && node.children) || {};
    var names = Object.keys(children).sort(function (a, b) {
      var da = children[a].type === "dir", db = children[b].type === "dir";
      if (da !== db) return da ? -1 : 1;
      return a.toLowerCase().localeCompare(b.toLowerCase());
    });

    if (names.length === 0) {
      var empty = document.createElement("div");
      empty.className = "files-empty";
      empty.textContent = "This folder is empty";
      list.appendChild(empty);
      return;
    }

    names.forEach(function (name) {
      var isDir = children[name].type === "dir";
      var item = document.createElement("div");
      item.className = "fs-item";
      item.title = name;

      var ic = document.createElement("div");
      ic.className = "icon";
      ic.textContent = iconFor(name, isDir);

      var nm = document.createElement("div");
      nm.className = "name";
      nm.textContent = name;

      item.appendChild(ic);
      item.appendChild(nm);

      item.addEventListener("click", function (e) {
        list.querySelectorAll(".fs-item.selected").forEach(function (el) {
          el.classList.remove("selected");
        });
        item.classList.add("selected");
        e.stopPropagation();
      });

      item.addEventListener("dblclick", function () {
        if (isDir) {
          currentPath = currentPath.concat(name);
          renderFiles();
        }
      });

      list.appendChild(item);
    });
  }

  document.getElementById("files-list").addEventListener("click", function () {
    this.querySelectorAll(".fs-item.selected").forEach(function (el) {
      el.classList.remove("selected");
    });
  });

  document.getElementById("files-up").addEventListener("click", function () {
    if (currentPath.length > 0) {
      currentPath = currentPath.slice(0, -1);
      renderFiles();
    }
  });

  document.getElementById("files-home").addEventListener("click", function () {
    currentPath = ["home", "user"];
    renderFiles();
  });

  renderFiles();

  /* ============ Notepad app ============ */
  var STORAGE_KEY = "ubuntu_notepad_state_v1";
  var state = { tabs: [], active: null, seq: 1 };

  function loadState() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        var parsed = JSON.parse(raw);
        if (parsed && Array.isArray(parsed.tabs)) {
          state = parsed;
          if (typeof state.seq !== "number") state.seq = state.tabs.length + 1;
        }
      }
    } catch (e) { /* ignore corrupt storage */ }

    if (!state.tabs || state.tabs.length === 0) {
      var id = "t" + (state.seq++);
      state.tabs = [{ id: id, name: "Untitled 1", content: "" }];
      state.active = id;
    }
    if (!state.active || !state.tabs.some(function (t) { return t.id === state.active; })) {
      state.active = state.tabs[0].id;
    }
  }

  function saveState() {
    try { localStorage.setItem(STORAGE_KEY, JSON.stringify(state)); } catch (e) {}
  }

  var tabsEl = document.getElementById("tabs");
  var newTabBtn = document.getElementById("new-tab");
  var editor = document.getElementById("editor");

  function activeTab() {
    return state.tabs.filter(function (t) { return t.id === state.active; })[0];
  }

  function renderTabs() {
    // remove existing tab elements (keep the + button)
    tabsEl.querySelectorAll(".tab").forEach(function (el) { el.remove(); });

    state.tabs.forEach(function (t) {
      var tab = document.createElement("div");
      tab.className = "tab" + (t.id === state.active ? " active" : "");
      tab.dataset.id = t.id;

      var nameEl = document.createElement("span");
      nameEl.className = "tab-name";
      nameEl.textContent = t.name || "Untitled";

      var closeEl = document.createElement("span");
      closeEl.className = "tab-close";
      closeEl.textContent = "×";

      tab.appendChild(nameEl);
      tab.appendChild(closeEl);

      tab.addEventListener("click", function (e) {
        if (e.target === closeEl) return;
        state.active = t.id;
        syncEditor();
        renderTabs();
        saveState();
      });

      closeEl.addEventListener("click", function (e) {
        e.stopPropagation();
        closeTab(t.id);
      });

      tabsEl.insertBefore(tab, newTabBtn);
    });
  }

  function syncEditor() {
    var t = activeTab();
    editor.value = t ? t.content : "";
  }

  function newTab() {
    var id = "t" + (state.seq++);
    var n = state.tabs.length + 1;
    state.tabs.push({ id: id, name: "Untitled " + n, content: "" });
    state.active = id;
    renderTabs();
    syncEditor();
    saveState();
    editor.focus();
  }

  function closeTab(id) {
    var idx = state.tabs.findIndex(function (t) { return t.id === id; });
    if (idx < 0) return;
    state.tabs.splice(idx, 1);
    if (state.tabs.length === 0) {
      var nid = "t" + (state.seq++);
      state.tabs.push({ id: nid, name: "Untitled 1", content: "" });
      state.active = nid;
    } else if (state.active === id) {
      state.active = state.tabs[Math.max(0, idx - 1)].id;
    }
    renderTabs();
    syncEditor();
    saveState();
  }

  // Derive tab name from first line of content.
  function updateTabName(t) {
    var firstLine = (t.content.split("\n")[0] || "").trim();
    t.name = firstLine ? firstLine.slice(0, 24) : "Untitled";
  }

  editor.addEventListener("input", function () {
    var t = activeTab();
    if (!t) return;
    t.content = editor.value;
    updateTabName(t);
    renderTabs();
    saveState();
  });

  newTabBtn.addEventListener("click", newTab);

  loadState();
  renderTabs();
  syncEditor();
})();
</script>
</body>
</html>
